FUNCTION_BLOCK FB_CalculateDayOfYear
VAR_INPUT
    Year : INT;
    Month : INT;
    Day : INT;
END_VAR

VAR_OUTPUT
    DayOfYear : INT;
    error : BOOL;
    status : WORD;
END_VAR

VAR_TEMP
    i : INT;
    IsLeapYear : BOOL;
    MaxDayForMonth : INT;
END_VAR

VAR
    DaysInMonth : ARRAY[1..12] OF INT := [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
END_VAR

(* Initialize outputs *)
DayOfYear := 0;
error := FALSE;
status := 0;

(* Validate Month - highest priority *)
IF (Month < 1) OR (Month > 12) THEN
    error := TRUE;
    status := 16#8002;
    RETURN;
END_IF;

(* Validate Year - lowest priority *)
IF (Year < 1000) OR (Year > 3000) THEN
    error := TRUE;
    status := 16#8001;
    RETURN;
END_IF;

(* Determine leap year *)
IsLeapYear := ((Year MOD 4) = 0) AND ((Year MOD 100) <> 0);
IsLeapYear := IsLeapYear OR ((Year MOD 400) = 0);

(* Determine maximum day for the given month *)
MaxDayForMonth := DaysInMonth[Month];
IF (Month = 2) AND IsLeapYear THEN
    MaxDayForMonth := 29;
END_IF;

(* Validate Day - second priority *)
IF (Day < 1) OR (Day > MaxDayForMonth) THEN
    error := TRUE;
    status := 16#8003;
    RETURN;
END_IF;

(* Calculate Day of Year *)
FOR i := 1 TO (Month - 1) DO
    DayOfYear := DayOfYear + DaysInMonth[i];
END_FOR;

DayOfYear := DayOfYear + Day;

(* Add extra day for leap year if month is after February *)
IF IsLeapYear AND (Month > 2) THEN
    DayOfYear := DayOfYear + 1;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SelectSort
VAR_INPUT
    exe : BOOL;
    seq : ARRAY[1..100] OF INT;
END_VAR
VAR_OUTPUT
    error : BOOL;
    status : WORD;
END_VAR
VAR
    i : INT;
    j : INT;
    minIndex : INT;
    temp : INT;
    n : INT := 100;
    seqLocal : ARRAY[1..100] OF INT;
    exePrev : BOOL;
    sortSuccessful : BOOL;
END_VAR

(* Initialize outputs *)
error := TRUE;
status := 16#8A01;
sortSuccessful := TRUE;

(* Execute sorting on rising edge of exe *)
IF exe AND NOT exePrev THEN
    (* Copy input array to local working array *)
    seqLocal := seq;

    (* Selection sort algorithm *)
    FOR i := 1 TO n-1 DO
        minIndex := i;

        FOR j := i+1 TO n DO
            IF seqLocal[j] < seqLocal[minIndex] THEN
                minIndex := j;
            END_IF;
        END_FOR;

        (* Swap elements if needed *)
        IF minIndex <> i THEN
            temp := seqLocal[i];
            seqLocal[i] := seqLocal[minIndex];
            seqLocal[minIndex] := temp;
        END_IF;
    END_FOR;

    (* Verify the array is sorted in ascending order *)
    sortSuccessful := TRUE;
    FOR i := 1 TO n-1 DO
        IF seqLocal[i] > seqLocal[i+1] THEN
            sortSuccessful := FALSE;
            EXIT;
        END_IF;
    END_FOR;

    (* Update outputs based on sorting result *)
    IF sortSuccessful THEN
        (* Copy sorted array back to output *)
        seq := seqLocal;
        error := FALSE;
        status := 16#0000;
    ELSE
        (* Sorting verification failed *)
        error := TRUE;
        status := 16#8A01;
    END_IF;
END_IF;

(* Store previous execution state *)
exePrev := exe;

END_FUNCTION_BLOCK

