            CASE autoStep OF
                1: (* Step 1: Open valve A *)
                    valveARun := TRUE;
                    valveBRun := FALSE;
                    valveCRun := FALSE;
                    valveDRun := FALSE;
                    mixMotorRun := FALSE;

