// Exit logic
IF exit_flag THEN
    found := FALSE;

    // Search from first row to last, first column to last
    FOR i := 1 TO 3 DO
        FOR j := 1 TO 5 DO
            IF garage[i, j].Occupied AND garage[i, j].VehicleNumber = VehicleNumber_in AND NOT found THEN
                // Found vehicle to exit
                truck_row := i;
