FUNCTION_BLOCK FB_MergeBytes
VAR_INPUT
    byteArray : ARRAY[1..20] OF DINT; (* Byte array to be merged *)
END_VAR
VAR_OUTPUT
    dwordArray : ARRAY[1..10] OF DINT; (* Merged double word array *)
    mergeDwordNum : DINT;
END_VAR
VAR
    i, j : DINT;
    tempDword : DWORD;
    bytePos : DINT;
    dwordPos : DINT;
    maxDwords : DINT;
END_VAR
VAR CONSTANT
    BYTE_ARRAY_SIZE : DINT := 20; (* Size of the input byte array *)
    DWORD_ARRAY_SIZE : DINT := 10; (* Size of the output DINT array *)
END_VAR

BEGIN
    mergeDwordNum := 0;

    (* Clear output array *)
    FOR i := 1 TO DWORD_ARRAY_SIZE DO
        dwordArray[i] := 0;
    END_FOR;

    (* Calculate maximum number of DWORDs we can merge *)
    maxDwords := MIN(BYTE_ARRAY_SIZE / 4, DWORD_ARRAY_SIZE);

    (* Merge bytes into DWORDs *)
    FOR dwordPos := 0 TO maxDwords - 1 DO
        tempDword := 0;
        bytePos := dwordPos * 4;

        (* Check if we have enough bytes remaining *)
        IF (bytePos + 4) <= BYTE_ARRAY_SIZE THEN
            (* Merge 4 bytes into 1 DWORD *)
            FOR j := 0 TO 3 DO
                (* Shift each byte into position and combine *)
                tempDword := tempDword OR (SHL(TO_DWORD(byteArray[bytePos + j + 1] AND 16#FF), (3 - j) * 8));
            END_FOR;

            (* Store the merged DWORD *)
            dwordArray[dwordPos + 1] := TO_DINT(tempDword);
            mergeDwordNum := mergeDwordNum + 1;
        END_IF;
    END_FOR;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_LinearizeValue
VAR_INPUT
    InputValue : REAL; // Floating point input, raw measurement value
END_VAR

VAR_OUTPUT
    LinearizedValue : REAL; // Converted linear value
    Error : BOOL; // Error status indicator
    Status : WORD; // Status code
END_VAR

VAR
    // No additional variables needed here
END_VAR

// Main execution logic
IF InputValue < 1200.0 THEN
    // Below minimum range
    LinearizedValue := 150.0;
    Error := TRUE;
    Status := 16#8001;
ELSIF InputValue >= 1200.0 AND InputValue < 3600.0 THEN
    // Range 1: 1200 to 3600
    LinearizedValue := 150.0 + (InputValue - 1200.0) * (240.0 - 150.0) / (3600.0 - 1200.0);
    Error := FALSE;
    Status := 16#0000;
ELSIF InputValue >= 3600.0 AND InputValue < 4800.0 THEN
    // Range 2: 3600 to 4800
    LinearizedValue := 240.0 + (InputValue - 3600.0) * (560.0 - 240.0) / (4800.0 - 3600.0);
    Error := FALSE;
    Status := 16#0000;
ELSIF InputValue >= 4800.0 AND InputValue <= 7000.0 THEN
    // Range 3: 4800 to 7000
    LinearizedValue := 560.0 + (InputValue - 4800.0) * (720.0 - 560.0) / (7000.0 - 4800.0);
    Error := FALSE;
    Status := 16#0000;
ELSE
    // Above maximum range
    LinearizedValue := 720.0;
    Error := TRUE;
    Status := 16#8001;
END_IF;

