FUNCTION_BLOCK FB_ProductionLineControl
VAR_INPUT
    Mode : BOOL;            // Manual/Auto mode selection
    ForwardButton : BOOL;   // Forward rotation button
    ReverseButton : BOOL;   // Reverse rotation button
    SensorA : BOOL;         // Sensor A input
    SensorB : BOOL;         // Sensor B input
    SensorC : BOOL;         // Sensor C input
    ButtonA : BOOL;         // Button A input
    ButtonB : BOOL;         // Button B input
    ButtonC : BOOL;         // Button C input
END_VAR

VAR_OUTPUT
    MotorForward : BOOL;    // Motor forward output
    MotorReverse : BOOL;    // Motor reverse output
    CompletionLight : BOOL; // Process completion indicator
END_VAR

VAR
    State : INT := 0;       // State machine current state
END_VAR

// Main logic
IF State = 0 THEN
    // Initialization state
    MotorForward := FALSE;
    MotorReverse := FALSE;
    CompletionLight := FALSE;
    State := 1;
END_IF;

IF NOT Mode THEN
    // Manual Mode Operation
    IF ForwardButton AND NOT ReverseButton THEN
        // Forward Motion
        MotorForward := TRUE;
        MotorReverse := FALSE;
    ELSIF ReverseButton AND NOT ForwardButton THEN
        // Reverse Motion
        MotorForward := FALSE;
        MotorReverse := TRUE;
    ELSE
        // Stop Condition (both pressed or neither pressed)
        MotorForward := FALSE;
        MotorReverse := FALSE;
    END_IF;

    // Reset state to 1 when switching to manual mode
    State := 1;
    CompletionLight := FALSE;
ELSE
    // Automatic Mode Operation
    CASE State OF
        1: // Waiting at Station A
            MotorForward := FALSE;
            MotorReverse := FALSE;
            IF SensorA THEN
                State := 2;
            END_IF;

        2: // Processing at Station A
            MotorForward := FALSE;
            MotorReverse := FALSE;
            IF ButtonA THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
                State := 3;
            END_IF;

        3: // Moving to Station B
            // Keep MotorForward TRUE from previous state
            MotorReverse := FALSE;
            IF SensorB THEN
                MotorForward := FALSE;
                State := 4;
            END_IF;

        4: // Processing at Station B
            MotorForward := FALSE;
            MotorReverse := FALSE;
            IF ButtonB THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
                State := 5;
            END_IF;

        5: // Moving to Station C
            // Keep MotorForward TRUE from previous state
            MotorReverse := FALSE;
            IF SensorC THEN
                MotorForward := FALSE;
                State := 6;
            END_IF;

        6: // Processing at Station C
            MotorForward := FALSE;
            MotorReverse := FALSE;
            IF ButtonC THEN
                CompletionLight := TRUE;
                State := 7;
            END_IF;

        7: // Cycle Completion
            MotorForward := FALSE;
            MotorReverse := FALSE;
            IF NOT SensorC THEN
                CompletionLight := FALSE;
                State := 1;
            END_IF;
    END_CASE;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_SplitNumber
VAR_INPUT
    InputNumber : INT;
END_VAR

VAR_OUTPUT
    Thousands : INT;
    Hundreds : INT;
    Tens : INT;
    Ones : INT;
    Min : INT;
    error : BOOL;
    status : WORD;
END_VAR

VAR
    tempNumber : INT;
    minValue : INT;
    digit1 : INT;
    digit2 : INT;
    digit3 : INT;
    digit4 : INT;
END_VAR

// Input validation
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    // Error condition
    error := TRUE;
    status := 16#8001;
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    // Valid input
    error := FALSE;
    status := 16#0000;

    // Digit separation
    Thousands := InputNumber / 1000;
    tempNumber := InputNumber MOD 1000;
    Hundreds := tempNumber / 100;
    tempNumber := tempNumber MOD 100;
    Tens := tempNumber / 10;
    Ones := tempNumber MOD 10;

    // Minimum non-zero digit detection
    minValue := 32767; // Maximum INT value

    // Check Thousands digit
    IF Thousands > 0 THEN
        minValue := minimal(minValue, Thousands);
    END_IF;

    // Check Hundreds digit
    IF Hundreds > 0 THEN
        minValue := minimal(minValue, Hundreds);
    END_IF;

    // Check Tens digit
    IF Tens > 0 THEN
        minValue := minimal(minValue, Tens);
    END_IF;

    // Check Ones digit
    IF Ones > 0 THEN
        minValue := minimal(minValue, Ones);
    END_IF;

    // Set Min output
    IF minValue = 32767 THEN
        // All digits are zero
        Min := 0;
    ELSE
        Min := minValue;
    END_IF;
END_IF;
END_FUNCTION_BLOCK

