    eActivating:
        SprinklersOn := FALSE;
        LastMoistureReading := SoilMoistureSensor;

        IF tDelay.Q THEN
            eState := eActive;
            bDelayActive := FALSE;
        END_IF;

        IF SoilMoistureSensor > 70.0 THEN
            eState := eIdle;
            bDelayActive := FALSE;
        END_IF;

    eActive:
        SprinklersOn := TRUE;
        bDelayActive := FALSE;
        LastMoistureReading := SoilMoistureSensor;

