    END_IF;

    // PPL4 to PPL5
    IF (PPL4 = TRUE) AND (MCBR = TRUE) AND MCBR_BUSY AND (PPL5 = FALSE) THEN
        PPL4 := FALSE;
        MCBR := FALSE;
        PPL5 := TRUE;
        STABLE := FALSE;
    END_IF;

    // PPL5 to PPL7
    IF (PPL5 = TRUE) AND S_AL1_MCBR2 AND (PPL7 = FALSE) AND (MCBR = FALSE) THEN
        PPL5 := FALSE;
        PPL7 := TRUE;
        MCBR := TRUE;
        STABLE := FALSE;
    END_IF;

    // PPL7 to End
    IF (PPL7 = TRUE) AND S_AL1_P_B3 THEN
        PPL7 := FALSE;
        STABLE := FALSE;
    END_IF;
END_WHILE;

// Output Control
// Set outputs based on active states
IF (PP0 = TRUE) OR (PP1 = TRUE) THEN
    E_AL1_B1 := TRUE;
ELSE
    E_AL1_B1 := FALSE;
END_IF;

IF (PP3 = TRUE) THEN
    MCB_CONTROL := TRUE;
ELSE
    MCB_CONTROL := FALSE;
END_IF;

IF (PPL3 = TRUE) OR (PPL4 = TRUE) THEN
    PAS_AL1_PLUS := TRUE;
    PAS_AL1_TURN := TRUE;
ELSE
    PAS_AL1_PLUS := FALSE;
    PAS_AL1_TURN := FALSE;
END_IF;

IF (PPAL1 = TRUE) OR (PP2 = TRUE) THEN
    PUWS_AL1_B1_PLUS := TRUE;
ELSE
    PUWS_AL1_B1_PLUS := FALSE;
END_IF;

IF (PP2 = TRUE) OR (PP3 = TRUE) OR (PPL3 = TRUE) THEN
    E_AL1_B1 := FALSE;
END_IF;

IF (PP0 = TRUE) OR (PP3 = TRUE) THEN
    MCB_CONTROL := FALSE;
END_IF;

IF (PP0 = TRUE) OR (PP3 = TRUE) OR (PP4 = TRUE) THEN
    PAS_AL1_PLUS := FALSE;
    PAS_AL1_TURN := FALSE;
END_IF;

IF (PPAL1 = TRUE) OR (PP2 = TRUE) THEN
    PUWS_AL1_B1_RIGHT := FALSE;
END_IF;

Main := TRUE;
END_METHOD

END_FUNCTION_BLOCK
